  1	import React, { FC } from 'react';
  2	import { Controller, useFormContext } from 'react-hook-form';
  3	
  4	import {
  5	  DropdownItem,
  6	  FileUpload,
  7	  FormGroup,
  8	  Text,
  9	  TextVariants,
 10	  Title,
 11	} from '@patternfly/react-core';
 12	import Select from '@utils/components/Select/Select';
 13	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 14	
 15	import {
 16	  CA_CERTIFICATE_FIELD_ID,
 17	  CERTIFICATE_FIELD_ID,
 18	  insecureTrafficTypes,
 19	  KEY_FIELD_ID,
 20	  PASSTHROUGH,
 21	  passthroughInsecureTrafficTypes,
 22	  terminationTypes,
 23	  TLS_TERMINATION_FIELD_ID,
 24	  TLS_TERMINATION_POLICY_FIELD_ID,
 25	} from './constants';
 26	
 27	const TLSTermination: FC = () => {
 28	  const { t } = useNetworkingTranslation();
 29	
 30	  const { control, watch } = useFormContext();
 31	
 32	  const terminationType = watch('spec.tls.termination');
 33	  const isPassthrough = terminationType === PASSTHROUGH;
 34	
 35	  return (
 36	    <>
 37	      <Controller
 38	        control={control}
 39	        name="spec.tls"
 40	        render={({ field: { onChange, value } }) => (
 41	          <FormGroup fieldId={TLS_TERMINATION_FIELD_ID} isRequired label={t('TLS termination')}>
 42	            <Select
 43	              id={TLS_TERMINATION_FIELD_ID}
 44	              selected={value?.termination}
 45	              toggleContent={terminationTypes[value?.termination] || t('Select termination type')}
 46	            >
 47	              <>
 48	                {Object.entries(terminationTypes).map(([type, label]) => (
 49	                  <DropdownItem
 50	                    key={type}
 51	                    onClick={() =>
 52	                      onChange({ ...value, insecureEdgeTerminationPolicy: '', termination: type })
 53	                    }
 54	                    value={type}
 55	                  >
 56	                    {label}
 57	                  </DropdownItem>
 58	                ))}
 59	              </>
 60	            </Select>
 61	          </FormGroup>
 62	        )}
 63	        rules={{ required: true }}
 64	      />
 65	      <Controller
 66	        control={control}
 67	        name="spec.tls"
 68	        render={({ field: { onChange, value } }) => (
 69	          <FormGroup fieldId={TLS_TERMINATION_POLICY_FIELD_ID} label={t('Insecure traffic')}>
 70	            <Select
 71	              id={TLS_TERMINATION_POLICY_FIELD_ID}
 72	              selected={value?.insecureEdgeTerminationPolicy}
 73	              toggleContent={
 74	                insecureTrafficTypes[value?.insecureEdgeTerminationPolicy] ||
 75	                t('Select insecure traffic type')
 76	              }
 77	            >
 78	              <>
 79	                {Object.entries(
 80	                  isPassthrough ? passthroughInsecureTrafficTypes : insecureTrafficTypes,
 81	                ).map(([type, label]) => (
 82	                  <DropdownItem
 83	                    key={type}
 84	                    onClick={() => onChange({ ...value, insecureEdgeTerminationPolicy: type })}
 85	                    value={type}
 86	                  >
 87	                    {label}
 88	                  </DropdownItem>
 89	                ))}
 90	              </>
 91	            </Select>
 92	          </FormGroup>
 93	        )}
 94	        rules={{ required: false }}
 95	      />
 96	
 97	      {terminationType && !isPassthrough && (
 98	        <Controller
 99	          control={control}
100	          name="spec.tls"
101	          render={({ field: { onChange, value } }) => (
102	            <>
103	              <Title headingLevel="h3">{t('Certificates')}</Title>
104	
105	              <Text component={TextVariants.p}>
106	                {t(
107	                  'TLS certificates for edge and re-encrypt termination. If not specified, the router&apos;s default certificate is used.',
108	                )}
109	              </Text>
110	
111	              <FormGroup fieldId={CERTIFICATE_FIELD_ID} label={t('Certificate')}>
112	                <FileUpload
113	                  id={CERTIFICATE_FIELD_ID}
114	                  onDataChange={(event, data) => onChange({ ...value, certificate: data })}
115	                  onFileInputChange={(event, data) => onChange({ ...value, certificate: data })}
116	                  onTextChange={(event, data) => onChange({ ...value, certificate: data })}
117	                  type="text"
118	                  value={value?.certificate}
119	                />
120	              </FormGroup>
121	
122	              <FormGroup fieldId={KEY_FIELD_ID} label={t('Private key')}>
123	                <FileUpload
124	                  id={KEY_FIELD_ID}
125	                  onDataChange={(event, data) => onChange({ ...value, key: data })}
126	                  onFileInputChange={(event, data) => onChange({ ...value, key: data })}
127	                  onTextChange={(event, data) => onChange({ ...value, key: data })}
128	                  type="text"
129	                  value={value?.key}
130	                />
131	              </FormGroup>
132	              <FormGroup fieldId={CA_CERTIFICATE_FIELD_ID} label={t('CA certificate')}>
133	                <FileUpload
134	                  id={CA_CERTIFICATE_FIELD_ID}
135	                  onDataChange={(event, data) => onChange({ ...value, caCertificate: data })}
136	                  onFileInputChange={(event, data) => onChange({ ...value, caCertificate: data })}
137	                  onTextChange={(event, data) => onChange({ ...value, caCertificate: data })}
138	                  type="text"
139	                  value={value?.caCertificate}
140	                />
141	              </FormGroup>
142	            </>
143	          )}
144	          rules={{ required: false }}
145	        />
146	      )}
147	    </>
148	  );
149	};
150	
151	export default TLSTermination;

